from itertools import product

class Solution:
    def minimumOR(self, grid) -> int:
        # Independent approach: literally enumerate every combination of one
        # value per row (feasible only for the small literal inputs this
        # oracle is checked against) and keep the smallest resulting OR.
        best = None
        for combo in product(*grid):
            v = 0
            for x in combo:
                v |= x
            if best is None or v < best:
                best = v
        return best

