class Solution:
    def minimumOR(self, grid) -> int:
        ans = 0
        for bit in range(19, -1, -1):
            mask = ans | ((1 << bit) - 1)
            ok = True
            for row in grid:
                if not any((v | mask) == mask for v in row):
                    ok = False
                    break
            if not ok:
                ans |= (1 << bit)
        return ans

solutions.javascript:
var minimumOR = function(grid) {
    let ans = 0;
    for (let bit = 19; bit >= 0; bit--) {
        const mask = ans | ((1 << bit) - 1);
        let ok = true;
        for (const row of grid) {
            let found = false;
            for (const v of row) {
                if ((v | mask) === mask) { found = true; break; }
            }
            if (!found) { ok = false; break; }
        }
        if (!ok) ans |= (1 << bit);
    }
    return ans;
};
